// Bucket proposals by category for per-commit runs.
// kategorieSlug drives the category, not the physical file.
const CATEGORY = {};
for (const [url, p] of Object.entries(PROPOSALS)) {
  const kat = url.split('/')[1]; // /finanzen/x → finanzen
  (CATEGORY[kat] = CATEGORY[kat] || []).push({ url, ...p });
}

function applyOne(filePath, oldMeta, newMeta) {
  const src = fs.readFileSync(filePath, 'utf8');
  const patterns = [
    `metaTitle: '${oldMeta.replace(/'/g, "\\'")}'`,
    `metaTitle: "${oldMeta.replace(/"/g, '\\"')}"`,
    `metaTitle: \`${oldMeta}\``,
  ];
  let hit = null, quoteIdx = -1;
  for (let i = 0; i < patterns.length; i++) {
    const p = patterns[i];
    const count = src.split(p).length - 1;
    if (count === 1) { hit = p; quoteIdx = i; break; }
    if (count > 1) throw new Error(`AMBIGUOUS (${count}x) in ${filePath}: ${p}`);
  }
  if (!hit) return { ok: false, reason: 'not found', file: filePath, old: oldMeta };
  let replacement;
  if (quoteIdx === 0)      replacement = `metaTitle: '${newMeta.replace(/'/g, "\\'")}'`;
  else if (quoteIdx === 1) replacement = `metaTitle: "${newMeta.replace(/"/g, '\\"')}"`;
  else                     replacement = `metaTitle: \`${newMeta}\``;
  fs.writeFileSync(filePath, src.replace(hit, replacement));
  return { ok: true };
}

function runCategory(cat) {
  const items = CATEGORY[cat];
  if (!items) { console.error('Unknown category:', cat); process.exit(2); }
  let changed = 0, skipped = 0;
  const errors = [];
  for (const it of items) {
    const cur = byUrl.get(it.url);
    if (!cur) { errors.push({ url: it.url, error: 'not in data-json' }); continue; }
    if (cur.metaTitle === it.newMeta) { skipped++; continue; }
    const file = CFG(it.file);
    try {
      const r = applyOne(file, cur.metaTitle, it.newMeta);
      if (r.ok) {
        changed++;
        const newLen = it.newMeta.length + 15;
        console.log(`  ✓ [${cat}] ${it.url} (${cur.renderedLen}→${newLen})`);
      } else {
        errors.push({ url: it.url, file, old: cur.metaTitle, reason: r.reason });
        console.log(`  ⚠ [${cat}] NOT FOUND in ${path.basename(file)}: ${it.url}`);
      }
    } catch (e) {
      errors.push({ url: it.url, file, old: cur.metaTitle, error: e.message });
      console.log(`  ✗ [${cat}] ERROR in ${path.basename(file)}: ${e.message}`);
    }
  }
  console.log(`\n${cat}: ${changed} metaTitles aktualisiert, ${skipped} unverändert.`);
  if (errors.length) {
    console.log('\nErrors / not-found:');
    for (const e of errors) console.log(' -', JSON.stringify(e));
    process.exit(3);
  }
}

const cat = process.argv[2];
if (!cat) { console.error('Usage: node scripts/apply-v2-titles.js <kategorie>'); process.exit(1); }
runCategory(cat);
